function cleanCity(value) {
  const text = String(value || '').trim().replace(/\s+/g, ' ');

  const naturalLanguageMatch = text.match(/(?:clima|tempo|temperatura|previs[a\u00e3]o).*?\b(?:em|de|da|do|no|na|para)\s+(.+)$/i);
  if (naturalLanguageMatch) {
    return naturalLanguageMatch[1].trim();
  }

  return text
    .replace(/^(qual\s+)?((e|\u00e9|eh)\s+)?(o\s+)?(clima|tempo|temperatura|previs[a\u00e3]o)\s*/i, '')
    .replace(/^(em|de|da|do|no|na|para)\s+/i, '')
    .trim();
}

return $input.all().map((item) => {
  const rawText = item.json.message?.text || '';
  const cleanedText = rawText.replace(/[?!;.]/g, ' ').replace(/\s+/g, ' ').trim();
  const parts = cleanedText.split(',').map((part) => part.trim()).filter(Boolean);

  let city = '';
  let state = '';
  let country = '';

  if (parts.length >= 3) {
    city = cleanCity(parts[0]);
    state = parts[1].replace(/[^A-Za-z]/g, '').toUpperCase();
    country = parts[2].replace(/[^A-Za-z]/g, '').toUpperCase();
  }

  const queue = city && state.length === 2 && country.length === 2
    ? `${city},${state},${country}`
    : '';

  const weatherQuery = queue
    ? `${city},${country}`
    : '';

  return {
    json: {
      ...item.json,
      chatId: item.json.message?.chat?.id,
      rawText,
      queue,
      weatherQuery,
    },
  };
});

const response = $input.first().json;
const original = $('Capturar e formatar entrada').item.json;
let body = response.body ?? response.data ?? response;

if (typeof body === 'string') {
  try {
    body = JSON.parse(body);
  } catch {
    body = {};
  }
}

const statusCode = Number(response.statusCode ?? body?.cod);
const temp = body?.main?.temp;
const ok = statusCode >= 200 && statusCode < 300 && temp !== undefined && temp !== null && Number.isFinite(Number(temp));
const fallbackCity = original.queue?.split(',')?.[0] || original.rawText || 'cidade informada';
const city = body?.name || fallbackCity;
const roundedTemp = ok ? Math.round(Number(temp)) : null;
const message = ok
  ? `\uD83C\uDF24\uFE0F A temperatura em ${city} \u00e9 de ${roundedTemp}\u00b0C.`
  : '\u274C Cidade n\u00e3o encontrada. Use o formato Cidade,UF,BR (ex.: S\u00e3o Paulo,SP,BR).';

return [
  {
    json: {
      ok,
      statusCode,
      city,
      temperature: roundedTemp,
      queue: original.queue,
      weatherQuery: original.weatherQuery,
      chatId: original.chatId,
      message,
    },
  },
];
